package com.restaurantcraft.util; import com.restaurantcraft.block.*; import com.restaurantcraft.blockentity.*; import com.restaurantcraft.config.RestaurantCraftConfig; import com.restaurantcraft.data.RestaurantLevel; import com.restaurantcraft.registry.ModBlocks; import net.minecraft.core.*; import net.minecraft.world.level.Level; import net.minecraft.world.level.block.Block; public class RestaurantAreaUtil { public record ScanResult(BlockPos min,BlockPos max,int tables,int chairs,BlockPos entrance,BlockPos exit,int decorPopularity){} public static ScanResult scan(Level l, RestaurantLevel lv, BlockPos center){int half=lv.range/2,y=RestaurantCraftConfig.maxVerticalScanRange.get(); BlockPos min=new BlockPos(center.getX()-half,center.getY()-y,center.getZ()-half),max=new BlockPos(center.getX()+half,center.getY()+y,center.getZ()+half); int t=0,c=0,decor=0; BlockPos en=null,ex=null; java.util.Map<com.restaurantcraft.data.DecorType,Integer> dec=new java.util.EnumMap<>(com.restaurantcraft.data.DecorType.class); for(BlockPos p:BlockPos.betweenClosed(min,max)){Block b=l.getBlockState(p).getBlock(); if(b==ModBlocks.RESTAURANT_TABLE.get())t++; if(b==ModBlocks.RESTAURANT_CHAIR.get())c++; if(b==ModBlocks.RESTAURANT_ENTRANCE.get()&&en==null)en=p.immutable(); if(b==ModBlocks.RESTAURANT_EXIT.get()&&ex==null)ex=p.immutable(); if(b instanceof DecorBlock d){int n=dec.getOrDefault(d.type,0); if(n<RestaurantCraftConfig.maxDecorCountPerType.get()){decor+=d.type.popularity;dec.put(d.type,n+1);}}} return new ScanResult(min,max,t,c,en,ex,decor);} public static boolean contains(RestaurantLevel lv, BlockPos center, BlockPos p){ScanResult r=scanMinMax(null,lv,center); return p.getX()>=r.min().getX()&&p.getX()<=r.max().getX()&&p.getY()>=r.min().getY()&&p.getY()<=r.max().getY()&&p.getZ()>=r.min().getZ()&&p.getZ()<=r.max().getZ();} private static ScanResult scanMinMax(Level l,RestaurantLevel lv,BlockPos c){int half=lv.range/2,y=RestaurantCraftConfig.maxVerticalScanRange.get();return new ScanResult(new BlockPos(c.getX()-half,c.getY()-y,c.getZ()-half),new BlockPos(c.getX()+half,c.getY()+y,c.getZ()+half),0,0,null,null,0);} public static boolean canPlaceRestaurantPart(Level l, BlockPos p, boolean table){ for(BlockPos c:BlockPos.betweenClosed(p.offset(-32,-8,-32),p.offset(32,8,32))) if(l.getBlockEntity(c) instanceof RestaurantManagementBlockEntity be && contains(be.level(),c,p)){ ScanResult r=scan(l,be.level(),c); return table ? r.tables()<be.level().tableLimit : r.chairs()<be.level().chairLimit; } return true; } public static void releaseChairs(Level l, BlockPos c, RestaurantLevel lv){ScanResult r=scan(l,lv,c); for(BlockPos p:BlockPos.betweenClosed(r.min,r.max)) if(l.getBlockEntity(p) instanceof RestaurantChairBlockEntity be)be.setOccupied(false);} public static void clearDevices(Level l, BlockPos c, RestaurantLevel lv){ScanResult r=scan(l,lv,c); for(BlockPos p:BlockPos.betweenClosed(r.min,r.max)){ if(l.getBlockEntity(p) instanceof CookingDeviceBlockEntity be)RestaurantInventoryUtil.clear(be.items); if(l.getBlockEntity(p) instanceof SinkBlockEntity be)RestaurantInventoryUtil.clear(be.items); }} }
